import 'package:flutter/services.dart' show rootBundle;
import 'package:http/http.dart' as http;
import 'dart:convert';

const String baseUrl = 'https://api.example.com';
const String apiKey = 'YOUR_API_KEY'; // Replace this with your actual API key

class Api {
  final http.Client _client;

  Api() : _client = http.Client();

  Future<http.Response> authenticate(String username, String password) async {
    var response = await _client.post(
      Uri.parse('$baseUrl/auth'),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({'username': username, 'password': password}),
    );

    if (response.statusCode == 200) {
      final Map<String, dynamic> data = jsonDecode(response.body);
      _saveToken(data['token']); // Save token for future requests
      return response;
    } else {
      throw Exception('Authentication failed');
    }
  }

  String _token;

  Future<String> _loadToken() async {
    final String jsonData = await rootBundle.loadString('assets/token.json');
    return jsonDecode(jsonData)['token'];
  }

  void _saveToken(String token) async {
    final Map<String, dynamic> data = {'token': token};
    final String jsonData = jsonEncode(data);
    await rootBundle.writeFile('assets/token.json', jsonData);
    this._token = token;
  }

  void _setHeaders(http.BaseRequest request) {
    if (_token != null) {
      request.headers['Authorization'] = 'Bearer $_token';
    }
  }

  Future<dynamic> getUserProfile() async {
    var response = await _client.get(Uri.parse('$baseUrl/profile'));
    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception('Failed to load user profile');
    }
  }

  Future<http.Response> synchronizeData() async {
    var response = await _client.get(Uri.parse('$baseUrl/synchronize'));
    if (response.statusCode == 200) {
      return response;
    } else {
      throw Exception('Failed to synchronize data');
    }
  }
}